function psOptions(){const el=$('#psSelect');if(!el)return[];return[...el.options].map(o=>cleanPs(o.value||o.textContent)).filter(Boolean).filter((x,i,a)=>a.indexOf(x)===i).sort((a,b)=>a.localeCompare(b,'th'))}
